INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-0489de64-moex-00381', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '政府對運輸行業的補貼是一種常見的管制手段，用於達到特定的經濟和社會目標。下列那項是運輸 補貼之目的？', '["提高私人運輸公司的利潤，從而增強其在國際市場上的競爭力", "確保交通工具的運行速度最大化，以提高整體運輸效率", "幫助減輕偏鄉地區的運輸成本，支持偏鄉地區公共交通系統，從而增進社會福祉和環境可持續性", "完全消除運輸業中的競爭，以便政府可以完全控制運輸市場"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00382', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '綠色機場是指透過實施各種環保和可持續性措施的機場，以減少對環境之影響。下列那項是綠色機 場常採用之措施？', '["大幅增加航班數量，以提高機場的服務效率和盈利能力", "在機場設施中廣泛使用可再生能源，如太陽能板和風力發電", "僅在白天運營機場，夜間關閉，以節省能源消耗", "限制機場內的自然光照，以減少能源用於照明的需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00383', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '電動巴士為充電需要，空駛（未載乘客）至場站充電之行駛成本，可歸類於下列何種成本？', '["聯合成本（jointcost）", "共同成本（commoncost）", "固定成本（fixedcost）", "附屬油料成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00384', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '根據汽車運輸業管理規則之規定，針對透過網際網路應用程式同時提供車輛租用及駕駛人代為駕駛 服務之小客車租賃業，下列敘述何者正確？', '["可將租用車輛運用於排班待客租賃", "提供之應用程式應提供車輛出廠年份訊息", "計費起租至少30分鐘以上", "營業車輛應黏貼交通部所定專用標章"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00385', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列對於A型專有路權、B型路權和C型路權之敘述，何者正確？', '["A型專有路權指某一交通工具在其運行過程中完全與其他交通工具隔離的運輸模式", "B型路權是指某一交通工具在部分路段獨立運行，而在另一部分路段與其他交通共享道路", "C型路權指所有相關的交通工具在整個運行過程中均採取共享道路的運輸模式", "所有的交通工具無論其種類，都應被視為C型路權，因為所有交通工具在某些情況下都會共享道路"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00386', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '適應性駕駛巡航系統（AdaptiveCruiseControl,ACC）可以幫助駕駛人控制與前車的距離，配備此系 統之車輛至少為國際自動機工程師學會（SAEInternational）定義之那一等級車輛輔助設計？', '["等級2", "等級3", "等級4", "等級5"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00387', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '國內規範高速公路增設交流道包含下列何者先決條件？①交通道間距至少應大於 2 公里  ②增設交', '["連絡道路車道配置至少為雙向四車道", "地方政府至 少負擔12%以上之總建設經費", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00388', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '鐵路列車為避免列車運轉時發生衝撞與追撞的危險，都會採取一些區隔方法來促使列車彼此保持一 個相當的安全空間。臺灣鐵路平溪支線的列車駕駛員常向上一站的站長拿一塊路牌轉交給下一站的 站長，這種列車區隔的閉塞方式稱之為：', '["電話電報閉塞", "電氣路籤（牌）閉塞", "自動閉塞", "移動閉塞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00389', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列何者為捷運系統在城市交通系統中之主要優勢？', '["捷運系統提供的車票價格永遠固定，不會因時間或路程長短而變化", "捷運車廂經常提供免費的咖啡和小吃", "捷運系統能有效減少城市交通擁擠，提供快速、可靠的公共交通服務", "所有捷運系統都能夠在水下行駛，連接城市的不同區域"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00390', 'elementary-0489de64', 'elementary-0489de64-moex-113-58eaf877', 'sub-elementary-0489de64-04', NULL, 'single_choice', '下列何者不是2020年運輸政策白皮書中提到「建構低碳、低污染之運輸環境」之策略？', '["逐步推動禁用機動車", "推動環島自行車道升級及多元路線整合", "推動運具電動化", "推動運輸業溫室氣體減量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:59+00:00", "source_pdf_sha1": "1e4c0f02d2ef", "answer_pdf_sha1": "ec07cdf52459", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0305", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "運輸學大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
